UPDATE erp_ship_logistics
SET is_default = 0
WHERE entity_type = #{entityType}
  AND entity_id = #{entityId}

mapper.select:
SELECT COUNT(*)
FROM erp_ship_logistics
WHERE entity_type = #{entityType}
  AND entity_id = #{entityId}
  AND logistics_id = #{logisticsId}
  AND shop_type = #{shopType}

SELECT *
FROM erp_ship_logistics
WHERE entity_type = #{entityType}
  AND entity_id = #{entityId}
  AND is_default = 1
LIMIT 1
